class TestRevocationEnforcement:

    def test_enforcement_gateway_called_on_revoke(
        self, mock_consent_service, mock_enforcement_gateway,
        consent_id, patient_id, revoked_consent_record
    ):
        """Revocation must trigger the enforcement gateway immediately."""
        mock_consent_service.revoke_consent.return_value = revoked_consent_record

        mock_consent_service.revoke_consent(
            consent_id=consent_id,
            revoked_by=patient_id,
            requesting_role=PATIENT_ROLE,
        )
        mock_enforcement_gateway.block_data_sharing(
            patient_id=patient_id, scope=DataSharingScope.CLINICAL
        )

        mock_enforcement_gateway.block_data_sharing.assert_called_once_with(
            patient_id=patient_id, scope=DataSharingScope.CLINICAL
        )

    def test_data_sharing_blocked_within_15_minutes(
        self, mock_consent_service, mock_enforcement_gateway,
        patient_id, revoked_consent_record, now
    ):
        """
        The enforcement timestamp recorded by the gateway must be within
        15 minutes of the revocation timestamp.
        """
        enforcement_time = now + timedelta(minutes=14, seconds=59)
        mock_enforcement_gateway.get_enforcement_timestamp.return_value = enforcement_time

        delta = enforcement_time - revoked_consent_record.revoked_at
        assert delta.total_seconds() <= ENFORCEMENT_DEADLINE_MINUTES * 60

    def test_data_sharing_blocked_exactly_at_15_minutes(
        self, revoked_consent_record, mock_enforcement_gateway, now
    ):
        """Boundary: enforcement at exactly T+15 min must still be compliant."""
        enforcement_time = revoked_consent_record.revoked_at + timedelta(minutes=15)
        mock_enforcement_gateway.get_enforcement_timestamp.return_value = enforcement_time

        delta = enforcement_time - revoked_consent_record.revoked_at
        assert delta.total_seconds() <= ENFORCEMENT_DEADLINE_MINUTES * 60

    def test_data_sharing_not_blocked_after_15_minutes_violates_sla(
        self, revoked_consent_record, mock_enforcement_gateway
    ):
        """
        If enforcement occurs after T+15 min, the SLA is violated.
        This test documents the unacceptable scenario.
        """
        late_enforcement = revoked_consent_record.revoked_at + timedelta(minutes=16)
        mock_enforcement_gateway.get_enforcement_timestamp.return_value = late_enforcement

        delta = late_enforcement - revoked_consent_record.revoked_at
        assert delta.total_seconds() > ENFORCEMENT_DEADLINE_MINUTES * 60  # SLA breach

    def test_data_sharing_disallowed_after_revocation(
        self, mock_consent_service, patient_id
    ):
        """After revocation, is_data_sharing_allowed must return False."""
        mock_consent_service.is_data_sharing_allowed.return_value = False

        result = mock_consent_service.is_data_sharing_allowed(
            patient_id=patient_id, scope=DataSharingScope.CLINICAL
        )

        assert result is False

    def test_data_sharing_allowed_before_revocation(
        self, mock_consent_service, patient_id
    ):
        """Before any revocation, is_data_sharing_allowed must return True."""
        mock_consent_service.is_data_sharing_allowed.return_value = True

        result = mock_consent_service.is_data_sharing_allowed(
            patient_id=patient_id, scope=DataSharingScope.CLINICAL
        )

        assert result is True

    def test_enforcement_called_for_all_revoked_scopes(
        self, mock_enforcement_gateway, patient_id, revoked_consent_record
    ):
        """Every scope in the revoked record must be blocked — not just one."""
        for scope in revoked_consent_record.scope:
            mock_enforcement_gateway.block_data_sharing(
                patient_id=patient_id, scope=scope
            )

        expected_calls = [
            call(patient_id=patient_id, scope=s)
            for s in revoked_consent_record.scope
        ]
        mock_enforcement_gateway.block_data_sharing.assert_has_calls(
            expected_calls, any_order=True
        )
        assert mock_enforcement_gateway.block_data_sharing.call_count == len(
            revoked_consent_record.scope
        )

    @pytest.mark.parametrize("elapsed_minutes", [1, 5, 10, 14])
    def test_enforcement_within_acceptable_window(
        self, revoked_consent_record, elapsed_minutes
    ):
        """Parametrised: enforcement at various sub-15-min points must be SLA-compliant."""
        enforcement_time = (
            revoked_consent_record.revoked_at + timedelta(minutes=elapsed_minutes)
        )
        delta = enforcement_time - revoked_consent_record.revoked_at
        assert delta.total_seconds() <= ENFORCEMENT_DEADLINE_MINUTES * 60


