class TestConflictingStateTransitions:

    def test_revoking_already_revoked_consent_raises_conflict(
        self, mock_consent_service, consent_id, patient_id, revoked_consent_record
    ):
        """Revoking an already-revoked consent must raise ConflictingStateError."""
        mock_consent_service.revoke_consent.side_effect = ConflictingStateError(
            "Consent is already REVOKED."
        )

        with pytest.raises(ConflictingStateError, match="already REVOKED"):
            mock_consent_service.revoke_consent(
                consent_id=consent_id,
                revoked_by=patient_id,
                requesting_role=PATIENT_ROLE,
            )

    def test_granting_already_granted_consent_raises_conflict(
        self, mock_consent_service, valid_grant_payload
    ):
        """Attempting to re-grant an active consent without explicit re-consent flow
        must raise ConflictingStateError to prevent silent duplicates."""
        mock_consent_service.grant_consent.side_effect = ConflictingStateError(
            "Active consent already exists for this patient and scope."
        )

        with pytest.raises(ConflictingStateError, match="already exists"):
            mock_consent_service.grant_consent(**valid_grant_payload)

    def test_revoking_expired_consent_raises_conflict(
        self, mock_consent_service, consent_id, patient_id, active_consent_record, now
    ):
        """Revoking an EXPIRED consent is semantically invalid."""
        active_consent_record.status = ConsentStatus.EXPIRED
        mock_consent_service.revoke_consent.side_effect = ConflictingStateError(
            "Cannot revoke an EXPIRED consent."
        )

        with pytest.raises(ConflictingStateError, match="EXPIRED"):
            mock_consent_service.revoke_consent(
                consent_id=consent_id,
                revoked_by=patient_id,
                requesting_role=PATIENT_ROLE,
            )

    def test_revoking_pending_consent_raises_conflict(
        self, mock_consent_service, consent_id, patient_id, active_consent_record
    ):
        """Revoking a PENDING consent (not yet activated) must be disallowed."""
        active_consent_record.status = ConsentStatus.PENDING
        mock_consent_service.revoke_consent.side_effect = ConflictingStateError(
            "Cannot revoke a PENDING consent; grant must be confirmed first."
        )

        with pytest.raises(ConflictingStateError, match="PENDING"):
            mock_consent_service.revoke_consent(
                consent_id=consent_id,
                revoked_by=patient_id,
                requesting_role=PATIENT_ROLE,
            )

    def test_revoking_non_existent_consent_raises_error(
        self, mock_consent_service, patient_id
    ):
        """Attempting to revoke a consent_id that does not exist must raise an error."""
        non_existent_id = str(uuid.uuid4())
        mock_consent_service.revoke_consent.side_effect = ConsentError(
            f"Consent record {non_existent_id} not found."
        )

        with pytest.raises(ConsentError):
            mock_consent_service.revoke_consent(
                consent_id=non_existent_id,
                revoked_by=patient_id,
                requesting_role=PATIENT_ROLE,
            )

    def test_concurrent_revocation_raises_conflict(
        self, mock_consent_service, consent_id, patient_id
    ):
